#!/usr/bin/env python3
# -*- coding: utf-8 -*-

import sys
import os

def main():
    n, m, k = map(int, sys.stdin.readline().split())
    a = [0]*(m+1)
    for i in range(m+1):
        a[i] = int(sys.stdin.readline())
    cnt = 0
    for i in range(m+1):
        for j in range(i+1, m+1):
            if bin(a[i] ^ a[j]).count('1') <= k:
                cnt += 1
    print(cnt)

if __name__ == "__main__":
    main()
